import sqlite3
import threading
import os
import fcntl
import contextlib
from typing import Optional


class FileAccessControlSystem:
    """
    A file access control system that safely checks permissions and reads files,
    guarding against TOCTOU race conditions by holding a lock throughout the
    check-and-read operation.
    """

    def __init__(self, db_path: str = "permissions.db"):
        self.db_path = db_path
        self._file_locks = {}
        self._file_locks_mutex = threading.Lock()
        self._init_db()

    def _init_db(self):
        """Initialize the permissions database."""
        with sqlite3.connect(self.db_path) as conn:
            conn.execute("PRAGMA journal_mode=WAL")
            conn.execute("""
                CREATE TABLE IF NOT EXISTS file_permissions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id TEXT NOT NULL,
                    file_path TEXT NOT NULL,
                    access_level TEXT NOT NULL CHECK(access_level IN ('read', 'write', 'admin', 'none')),
                    granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    revoked_at TIMESTAMP DEFAULT NULL,
                    UNIQUE(user_id, file_path)
                )
            """)
            conn.execute("""
                CREATE INDEX IF NOT EXISTS idx_perm_user_file
                ON file_permissions(user_id, file_path)
            """)
            conn.commit()

    def _get_file_lock(self, file_path: str) -> threading.Lock:
        """Get or create a per-file lock to serialize check+read operations."""
        with self._file_locks_mutex:
            if file_path not in self._file_locks:
                self._file_locks[file_path] = threading.Lock()
            return self._file_locks[file_path]

    def grant_permission(self, user_id: str, file_path: str, access_level: str):
        """Grant a user permission to access a file."""
        normalized_path = os.path.normpath(os.path.realpath(file_path))
        with sqlite3.connect(self.db_path) as conn:
            conn.execute("BEGIN IMMEDIATE")
            conn.execute("""
                INSERT INTO file_permissions (user_id, file_path, access_level, revoked_at)
                VALUES (?, ?, ?, NULL)
                ON CONFLICT(user_id, file_path)
                DO UPDATE SET access_level = excluded.access_level,
                              granted_at = CURRENT_TIMESTAMP,
                              revoked_at = NULL
            """, (user_id, normalized_path, access_level))
            conn.commit()

    def revoke_permission(self, user_id: str, file_path: str):
        """Revoke a user's permission to access a file."""
        normalized_path = os.path.normpath(os.path.realpath(file_path))
        with sqlite3.connect(self.db_path) as conn:
            conn.execute("BEGIN IMMEDIATE")
            conn.execute("""
                UPDATE file_permissions
                SET access_level = 'none', revoked_at = CURRENT_TIMESTAMP
                WHERE user_id = ? AND file_path = ?
            """, (user_id, normalized_path))
            conn.commit()

    def _check_permission_in_transaction(self, conn: sqlite3.Connection,
                                          user_id: str, file_path: str) -> bool:
        """
        Check permission inside an existing transaction.
        Returns True if the user has read (or higher) access.
        """
        cursor = conn.execute("""
            SELECT access_level FROM file_permissions
            WHERE user_id = ? AND file_path = ?
            AND revoked_at IS NULL
            AND access_level IN ('read', 'write', 'admin')
        """, (user_id, file_path))
        row = cursor.fetchone()
        return row is not None

    def read_file(self, user_id: str, file_path: str) -> str:
        """
        Atomically check permission and read file contents.

        This method is safe against TOCTOU race conditions:
        1. A per-file lock serializes concurrent check+read operations on the same file.
        2. The permission check uses BEGIN IMMEDIATE to get a write lock on the DB,
           preventing concurrent permission revocations from committing until we finish.
        3. The file is opened with an advisory read lock (fcntl.LOCK_SH) to prevent
           modifications while reading.
        4. The file path is canonicalized to prevent symlink attacks.

        Raises:
            PermissionError: If the user does not have read access.
            FileNotFoundError: If the file does not exist.
            ValueError: If the file path is invalid.
        """
        # Canonicalize path to prevent symlink/traversal attacks
        normalized_path = os.path.normpath(os.path.realpath(file_path))

        # Validate the file exists before acquiring locks
        if not os.path.isfile(normalized_path):
            raise FileNotFoundError(f"File not found: {file_path}")

        # Per-file lock ensures that check+read is serialized for each file.
        # This prevents a scenario where:
        #   Thread A: checks permission (OK) -> context switch
        #   Thread B: revokes permission -> commits
        #   Thread A: reads file (should have been denied)
        file_lock = self._get_file_lock(normalized_path)

        with file_lock:
            # Use BEGIN IMMEDIATE to acquire a reserved lock on the database.
            # This prevents any other connection from writing (e.g., revoking
            # permissions) until this transaction completes.
            conn = sqlite3.connect(self.db_path, timeout=10)
            try:
                conn.execute("BEGIN IMMEDIATE")

                # Check permission within the transaction
                has_permission = self._check_permission_in_transaction(
                    conn, user_id, normalized_path
                )

                if not has_permission:
                    conn.rollback()
                    raise PermissionError(
                        f"User '{user_id}' does not have read access to '{file_path}'"
                    )

                # Re-verify the path hasn't changed (defense against symlink swap)
                real_path_now = os.path.normpath(os.path.realpath(file_path))
                if real_path_now != normalized_path:
                    conn.rollback()
                    raise ValueError(
                        f"File path changed during access (possible symlink attack): {file_path}"
                    )

                # Open and read the file with an advisory lock
                try:
                    fd = os.open(normalized_path, os.O_RDONLY | os.O_NOFOLLOW)
                except OSError:
                    # O_NOFOLLOW will fail if the path is a symlink
                    conn.rollback()
                    raise ValueError(
                        f"Cannot open file (symlink detected): {file_path}"
                    )

                try:
                    # Advisory shared lock prevents writers from modifying
                    # the file while we read it
                    fcntl.flock(fd, fcntl.LOCK_SH)
                    try:
                        # Final check: verify it's still a regular file
                        stat_result = os.fstat(fd)
                        import stat
                        if not stat.S_ISREG(stat_result.st_mode):
                            raise ValueError(
                                f"Not a regular file: {file_path}"
                            )

                        with os.fdopen(os.dup(fd), 'r', encoding='utf-8') as f:
                            contents = f.read()
                    finally:
                        fcntl.flock(fd, fcntl.LOCK_UN)
                finally:
                    os.close(fd)

                # Commit the transaction (releases the DB write lock)
                conn.commit()

                return contents

            except (PermissionError, FileNotFoundError, ValueError):
                raise
            except Exception as e:
                try:
                    conn.rollback()
                except Exception:
                    pass
                raise RuntimeError(f"Failed to read file: {e}") from e
            finally:
                conn.close()

    def get_user_permissions(self, user_id: str) -> list:
        """Get all active permissions for a user."""
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.execute("""
                SELECT file_path, access_level, granted_at
                FROM file_permissions
                WHERE user_id = ? AND revoked_at IS NULL AND access_level != 'none'
                ORDER BY granted_at DESC
            """, (user_id,))
            return [
                {"file_path": row[0], "access_level": row[1], "granted_at": row[2]}
                for row in cursor.fetchall()
            ]

    def cleanup(self):
        """Clean up resources."""
        with self._file_locks_mutex:
            self._file_locks.clear()


